external_knowledge:
- 'set sail on the journey of bike riding' refers to the initiation of bike rentals;
- 'count of both casual and registered voyagers' refers to the total number of casual and registered users;
- 'tale of the most frequent starters' refers to the total number of users initiating rentals, sorted in descending order.

sql:
SELECT season, total_users
FROM bike_usage
WHERE total_users > 10;

SELECT AVG(temp) AS Average_Temperature
FROM bike_usage
WHERE holiday = 1;

SELECT STRFTIME('%H', start_time) AS hour, COUNT(bike_id) AS num_bikes_rented
FROM rentals
GROUP BY STRFTIME('%H', start_time);

SELECT weather_condition, MIN(temperature) AS min_temperature, MAX(temperature) AS max_temperature
FROM weather
GROUP BY weather_condition;

SELECT COUNT(*) 
FROM rentals 
WHERE start_time <> "" AND end_time <> "" AND payment_amount > 0;

SELECT DISTINCT s.station_id, s.location
FROM bike_usage AS bu
JOIN stations AS s ON bu.station_id = s.station_id;

SELECT user_id, AVG(duration_minutes) AS avg_duration
FROM rentals
GROUP BY user_id;

SELECT COUNT(*) AS total_number_of_rentals
FROM rentals
WHERE end_time IS NOT NULL;

SELECT AVG(count_rentals) AS average_rentals
FROM (
  SELECT station_id, COUNT(rental_id) AS count_rentals
  FROM rentals
  GROUP BY station_id
) AS station_rentals;

